function PricingSection() {
  const plans = [
    { name: 'Starter', price: '$9', period: '/month', features: ['5 projects', '10GB storage', 'Email support'] },
    { name: 'Pro', price: '$29', period: '/month', features: ['Unlimited projects', '100GB storage', 'Priority support', 'API access'], recommended: true },
    { name: 'Enterprise', price: '$99', period: '/month', features: ['Everything in Pro', 'Unlimited storage', 'Dedicated support', 'Custom integrations', 'SLA guarantee'] }
  ];

  return (
    <section className="py-16 px-4">
      <div className="text-center mb-12">
        <h2 className="text-h2 text-grey-900">Simple, transparent pricing</h2>
        <p className="text-body-lg text-grey-500 mt-4">Choose the plan that's right for you</p>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8 max-w-5xl mx-auto">
        {plans.map((plan) => (
          <div
            key={plan.name}
            className={`p-8 rounded-xl border ${plan.recommended ? 'border-primary-500 shadow-soft-md' : 'border-grey-200'}`}
          >
            {plan.recommended && (
              <Badge color="orange" className="mb-4">Most Popular</Badge>
            )}
            <h3 className="text-h4 text-grey-900">{plan.name}</h3>
            <div className="mt-4">
              <span className="text-display-sm text-grey-900">{plan.price}</span>
              <span className="text-body-md text-grey-500">{plan.period}</span>
            </div>
            <ul className="mt-6 space-y-3">
              {plan.features.map((feature) => (
                <li key={feature} className="flex items-center gap-2 text-body-md text-grey-700">
                  <Icon name="check" className="text-success-500" size="sm" />
                  {feature}
                </li>
              ))}
            </ul>
            <Button
              variant={plan.recommended ? 'primary' : 'grey'}
              appearance={plan.recommended ? 'solid' : 'outlined'}
              className="w-full mt-8"
            >
              Get Started
            </Button>
          </div>
        ))}
      </div>
    </section>
  );
}

