function StatsCards() {
  const stats = [
    { title: 'Total Revenue', value: '$45,231', trend: { label: '+20.1%', type: 'up' } },
    { title: 'Active Users', value: '2,543', trend: { label: '+15.3%', type: 'up' } },
    { title: 'Conversion Rate', value: '3.24%', trend: { label: '-2.1%', type: 'down' } },
    { title: 'Avg. Order Value', value: '$124', trend: { label: '+8.4%', type: 'up' } }
  ];

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 p-6">
      {stats.map((stat) => (
        <MetricsCard
          key={stat.title}
          title={stat.title}
          value={stat.value}
