}

function LoginForm() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [remember, setRemember] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();
    // Handle login
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-grey-50 py-12 px-4">
      <div className="max-w-md w-full bg-white rounded-xl shadow-soft-md p-8">
        <div className="text-center mb-8">
          <h1 className="text-h4 text-grey-900">Welcome back</h1>
          <p className="text-body-md text-grey-500 mt-2">Sign in to your account</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <Input
            label="Email"
            type="email"
            placeholder="you@example.com"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            leadingIcon="mail"
          />
          <Input
            label="Password"
            type="password"
            placeholder="••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            leadingIcon="lock"
          />

          <div className="flex items-center justify-between">
            <Checkbox
              label="Remember me"
              checked={remember}
              onChange={(e) => setRemember(e.target.checked)}
            />
            <a href="/forgot-password" className="text-body-sm text-primary-500 hover:text-primary-600">
              Forgot password?
            </a>
          </div>

          <Button type="submit" variant="primary" className="w-full">
            Sign in
          </Button>
        </form>

        <Divider label="OR" className="my-6" />

        <Button variant="grey" appearance="outlined" className="w-full" icon="github" iconPosition="leading">
          Continue with GitHub
        </Button>

        <p className="text-center text-body-sm text-grey-500 mt-6">
          Don't have an account?{' '}
          <a href="/signup" className="text-primary-500 hover:text-primary-600 font-medium">
            Sign up
          </a>
        </p>
      </div>
    </div>
  );
}

function SignupForm() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: ''
  });
  const [agreed, setAgreed] = useState(false);

  const handleChange = (field) => (e) => {
    setFormData({ ...formData, [field]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Handle signup
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-grey-50 py-12 px-4">
      <div className="max-w-md w-full bg-white rounded-xl shadow-soft-md p-8">
        <div className="text-center mb-8">
          <h1 className="text-h4 text-grey-900">Create your account</h1>
          <p className="text-body-md text-grey-500 mt-2">Start your 14-day free trial</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <Input
            label="Full name"
            placeholder="John Doe"
            value={formData.name}
            onChange={handleChange('name')}
            leadingIcon="user"
          />
          <Input
            label="Email"
            type="email"
            placeholder="you@example.com"
            value={formData.email}
            onChange={handleChange('email')}
            leadingIcon="mail"
          />
          <Input
            label="Password"
            type="password"
            placeholder="Create a password"
            value={formData.password}
            onChange={handleChange('password')}
            leadingIcon="lock"
            helperText="Must be at least 8 characters"
          />
          <Input
            label="Confirm password"
            type="password"
            placeholder="Confirm your password"
            value={formData.confirmPassword}
            onChange={handleChange('confirmPassword')}
            leadingIcon="lock"
            error={formData.confirmPassword && formData.password !== formData.confirmPassword ? 'Passwords do not match' : undefined}
          />

          <Checkbox
            label="I agree to the Terms of Service and Privacy Policy"
            checked={agreed}
            onChange={(e) => setAgreed(e.target.checked)}
          />

          <Button type="submit" variant="primary" className="w-full" disabled={!agreed}>
            Create account
          </Button>
        </form>

        <p className="text-center text-body-sm text-grey-500 mt-6">
          Already have an account?{' '}
          <a href="/login" className="text-primary-500 hover:text-primary-600 font-medium">
            Sign in
          </a>
        </p>
      </div>
    </div>
  );
}
